function deriveSseName(url) {
	if (!url) return "";
	try {
		var hostname = new URL(url.trim()).hostname;
		var parts = hostname.split(".").filter((p) => p !== "mcp" && p !== "www");
		return parts.length > 0 ? parts[0].toLowerCase() : "";
	} catch {
		return "";
	}
}

