            .with_status(200)
            .with_header("content-type", "application/json")
            .with_body(r#"{"jsonrpc":"2.0","id":1,"result":{"ok":true}}"#)
            .create_async()
            .await;

        let auth = Arc::new(CountingAuthProvider {
            reauth_calls: AtomicUsize::new(0),
        });
