			configuring.value &&
			html`<div class="px-3 pb-3 border border-t-0 border-[var(--border)] rounded-b-[var(--radius-sm)]">
	        <${ConfigForm} server=${f} argsVal=${argsVal} envVal=${envVal} urlVal=${urlVal} headerVal=${headerVal} timeoutVal=${timeoutVal} onCancel=${() => {
