 58→async fn agent_exists_for_ctx(ctx: &MethodContext, agent_id: &str) -> bool {
 59→    if agent_id == "main" {
 60→        return true;
 61→    }
 62→    if let Some(ref store) = ctx.state.services.agent_persona_store {
 63→        return store.get(agent_id).await.ok().flatten().is_some();
 64→    }
 65→    false
 66→}
