 68→async fn resolve_session_agent_id_for_ctx(ctx: &MethodContext) -> String {
 69→    let default_id = default_agent_id_for_ctx(ctx).await;
 70→    let Some(session_key) = active_session_key_for_ctx(ctx).await else {
 71→        return default_id;
 72→    };
 73→    let Some(ref metadata) = ctx.state.services.session_metadata else {
 74→        return default_id;
 75→    };
 76→    let Some(entry) = metadata.get(&session_key).await else {
 77→        return default_id;
 78→    };
 79→    let Some(agent_id) = entry
 80→        .agent_id
 81→        .as_deref()
 82→        .map(str::trim)
 83→        .filter(|value| !value.is_empty())
 84→    else {
 85→        return default_id;
 86→    };
 87→    if agent_exists_for_ctx(ctx, agent_id).await {
 88→        return agent_id.to_string();
 89→    }
 90→    warn!(
 91→        session = %session_key,
 92→        agent_id,
 93→        fallback = %default_id,
 94→        "session references unknown agent, falling back to default"
 95→    );
 96→    let _ = metadata.set_agent_id(&session_key, Some(&default_id)).await;
 97→    default_id
 98→}
