                    .map_err(ErrorShape::from)?;

                let provider_name = result
                    .get("provider")
                    .and_then(|v| v.as_str())
                    .map(ToOwned::to_owned);

                // Kick off background support probing after OAuth provider connect.
                let model_service = Arc::clone(&ctx.state.services.model);
