    #[test]
    fn parse_server_config_allows_sse_without_command() {
        let cfg = parse_server_config(
            &serde_json::json!({
                "transport": "sse",
                "url": "https://mcp.linear.app/mcp",
                "enabled": true
            }),
            None,
        );
        assert!(
            cfg.is_ok(),
